INSERT INTO site_settings (id, `key`, locale, value) VALUES
('55891948-6191-d877-48a9-cd81352ba9ff', 'ui_about_author_bio', '*', '{"label":{"tr":"GoldMoodAstro içerikleri; astroloji, tarot, numeroloji ve ruhsal danışmanlık başlıklarını kullanıcıların karar anlarında daha sakin, bilinçli ve kendilerine yakın hissetmeleri için hazırlar.","en":"GoldMoodAstro content prepares astrology, tarot, numerology and spiritual consulting topics so users can feel calmer, more conscious and closer to themselves at decision moments.","de":"GoldMoodAstro Inhalte bereiten Astrologie, Tarot, Numerologie und spirituelle Beratung so auf, dass Nutzer in Entscheidungsmomenten ruhiger, bewusster und näher bei sich selbst sein können."}}'),
('f1498c72-46eb-f7ff-bffc-f9390bbdf073', 'ui_about_diff_items', '*', '{"label":{"tr":"[{\\"title\\":\\"Şeffaf uzman seçimi\\",\\"body\\":\\"Kullanıcılar danışman profillerini, uzmanlıklarını, paketlerini, puanlarını ve müsaitliklerini tek ekranda karşılaştırabilir. Böylece seans, belirsiz bir deneme yerine bilinçli bir seçimle başlar.\\"},{\\"title\\":\\"Teknik olarak bütünleşik seans akışı\\",\\"body\\":\\"Randevu, ödeme, hatırlatma, mesaj ve uygulama içi sesli görüşme aynı platform mantığında çalışır. Kullanıcı ve danışman için dağınık araçlar yerine tek, sakin ve takip edilebilir bir deneyim hedeflenir.\\"},{\\"title\\":\\"Sorumlu ruhsal rehberlik dili\\",\\"body\\":\\"GoldMoodAstro korku, manipülasyon veya kesin kader söylemi üzerine kurulmaz. İçerik ve seans dili; farkındalık, seçenekler, kişisel sorumluluk ve duygusal güvenlik ilkeleriyle şekillenir.\\"}]","en":"[{\\"title\\":\\"Transparent expert selection\\",\\"body\\":\\"Users can compare consultant profiles, specialties, packages, ratings and availability on one screen. The session begins with a conscious choice instead of an uncertain trial.\\"},{\\"title\\":\\"Technically integrated session flow\\",\\"body\\":\\"Booking, payment, reminders, messages and in-app voice sessions work within the same platform logic. The goal is one calm and trackable experience instead of scattered tools.\\"},{\\"title\\":\\"Responsible spiritual guidance language\\",\\"body\\":\\"GoldMoodAstro is not built on fear, manipulation or absolute fate claims. Content and session language are shaped by awareness, options, personal responsibility and emotional safety.\\"}]","de":"[{\\"title\\":\\"Transparente Expertenwahl\\",\\"body\\":\\"Nutzer können Beraterprofile, Fachgebiete, Pakete, Bewertungen und Verfügbarkeit auf einem Bildschirm vergleichen. So beginnt eine Sitzung mit einer bewussten Wahl statt mit einem unklaren Versuch.\\"},{\\"title\\":\\"Technisch integrierter Sitzungsablauf\\",\\"body\\":\\"Termin, Zahlung, Erinnerung, Nachricht und In-App-Sprachgespräch funktionieren innerhalb derselben Plattformlogik. Ziel ist eine ruhige und nachvollziehbare Erfahrung statt verstreuter Werkzeuge.\\"},{\\"title\\":\\"Verantwortungsvolle Sprache der spirituellen Begleitung\\",\\"body\\":\\"GoldMoodAstro baut nicht auf Angst, Manipulation oder absolute Schicksalsbehauptungen. Inhalte und Sitzungssprache werden von Bewusstsein, Optionen, persönlicher Verantwortung und emotionaler Sicherheit geprägt.\\"}]"}}'),
('e4b9017c-3bbb-8413-9f55-b9a9b4c434aa', 'ui_about_diff_title', '*', '{"label":{"tr":"Neden GoldMood?","en":"Why GoldMood?","de":"Warum GoldMood?"}}'),
('dc2ba964-9e8c-ac76-fe5c-989c478b07ca', 'ui_about_experience_paragraphs', '*', '{"label":{"tr":"[\\"GoldMoodAstro ekibi; yazılım geliştirme, ürün tasarımı, astroloji, tarot, içerik editörlüğü ve kullanıcı deneyimi alanlarının birleşiminden oluşur. Kombine deneyimimizi yalnızca yıl sayısıyla değil, kullanıcıya temas eden her küçük akışta ölçüyoruz: danışman bulma, uygun saat seçme, ödeme, hatırlatma, sesli görüşme, mesajlaşma ve görüşme sonrası değerlendirme.\\",\\"Danışmanlarımız farklı uzmanlıklardan gelir: doğum haritası, ilişki astrolojisi, tarot, numeroloji, mood danışmanlığı, kariyer ve ilişki odaklı rehberlik. Her profilin uzmanlık alanı, dil bilgisi, seans paketi ve kullanıcı yorumları görünür olmalıdır. Çünkü güven, güzel cümlelerden önce şeffaf bilgiyle başlar.\\",\\"Bu deneyim anlayışı mobil uygulama, web arayüzü ve danışman panelinde aynen devam eder. Kullanıcı için önemli olan, ne zaman kiminle görüşeceğini ve görüşmenin ona ne sağlayabileceğini net biçimde bilmektir. Danışman için önemli olan ise zamanını, paketlerini, uygunluk durumunu ve kullanıcı iletişimini düzenli yönetebilmektir. GoldMoodAstro bu iki tarafı aynı ciddiyetle ele alır. Çünkü iyi bir seans yalnızca doğru yorumla değil, o yorumun gerçekleştiği güvenli operasyonel ortamla da ilgilidir.\\"]","en":"[\\"The GoldMoodAstro team combines software development, product design, astrology, tarot, editorial work and user experience. We measure combined experience not only in years, but in every small flow that touches the user: finding a consultant, choosing a suitable time, paying, receiving reminders, joining a voice session, messaging and reviewing after the session.\\",\\"Our consultants come from different areas of expertise: birth charts, relationship astrology, tarot, numerology, mood consulting, career and relationship-focused guidance. Each profile should clearly show expertise, languages, session package and user reviews. Trust begins with transparent information before beautiful sentences.\\",\\"This understanding of experience continues in the mobile app, web interface and consultant panel. What matters for users is knowing clearly when and with whom they will meet, and what the session may offer them. What matters for consultants is managing their time, packages, availability and user communication in an orderly way. GoldMoodAstro takes both sides seriously, because a good session depends not only on the right interpretation but also on the safe operational environment in which that interpretation happens.\\"]","de":"[\\"Das GoldMoodAstro Team verbindet Softwareentwicklung, Produktdesign, Astrologie, Tarot, Redaktion und User Experience. Unsere gemeinsame Erfahrung messen wir nicht nur in Jahren, sondern in jedem kleinen Ablauf, der Nutzer berührt: Berater finden, passende Zeit wählen, bezahlen, erinnert werden, Sprachgespräch starten, schreiben und nach der Sitzung bewerten.\\",\\"Unsere Berater kommen aus unterschiedlichen Fachgebieten: Geburtshoroskop, Beziehungsastrologie, Tarot, Numerologie, Mood-Beratung, Karriere und beziehungsorientierte Begleitung. Jedes Profil sollte Fachgebiet, Sprachen, Sitzungspaket und Nutzerbewertungen klar zeigen. Vertrauen beginnt vor schönen Sätzen mit transparenter Information.\\",\\"Dieses Verständnis von Erfahrung setzt sich in der mobilen App, der Weboberfläche und dem Beraterpanel fort. Für Nutzer ist wichtig, klar zu wissen, wann sie mit wem sprechen und was die Sitzung ihnen geben kann. Für Berater ist wichtig, Zeit, Pakete, Verfügbarkeit und Nutzerkommunikation ordentlich verwalten zu können. GoldMoodAstro nimmt beide Seiten gleich ernst, denn eine gute Sitzung hängt nicht nur von der richtigen Deutung ab, sondern auch von der sicheren operativen Umgebung, in der sie stattfindet.\\"]"}}'),
('cb29dbe2-e5f0-d2f0-0e51-f50ceb62a5a4', 'ui_about_experience_title', '*', '{"label":{"tr":"Ekip ve Deneyim","en":"Team and Experience","de":"Team und Erfahrung"}}'),
('b0243495-b0c4-066e-810b-41e030829b76', 'ui_about_eyebrow', '*', '{"label":{"tr":"GoldMoodAstro Manifestosu","en":"GoldMoodAstro Manifesto","de":"GoldMoodAstro Manifest"}}'),
('01944256-eabb-7450-110f-782e5acd2548', 'ui_about_founder_paragraphs', '*', '{"label":{"tr":"[\\"GoldMoodAstro fikri, Pınar Demircioğlu’nun ruhsal danışmanlık vizyonuyla insanların hayatlarında daha kişisel, daha güven veren ve daha kolay ulaşılabilir rehberlik arayışını bir araya getirme isteğinden doğdu. Pınar için iyi bir platform yalnızca hızlı çalışan ekranlardan ibaret değildir; kullanıcıyı doğru uzmana taşıyan, ödeme ve randevu akışını güvenle çözen, seans başladığında teknik detayları aradan kaldıran görünmez bir düzen demektir.\\",\\"Bu nedenle GoldMoodAstro’da teknoloji, spiritüel danışmanlığın önüne geçmez; ona alan açar. Kullanıcı danışman seçerken profil, uzmanlık, yorum, seans süresi ve ücret gibi bilgileri şeffaf biçimde görür. Danışman ise kendi takvimini, paketlerini, mesajlarını ve görüşmelerini yönetebileceği profesyonel bir panelle çalışır. Kurucu perspektifimiz basittir: ruhsal rehberlik, dijital dünyada da özenli, etik ve anlaşılır olabilir.\\",\\"GoldMoodAstro’nun ilk hedefi astroloji veya tarot merakını tek seferlik bir eğlenceye indirgemek değil, danışmanla kullanıcı arasında güvenli bir konuşma zemini kurmaktır. Bazen bir doğum haritası kişinin tekrar eden ilişki döngülerini görmesine yardımcı olur. Bazen bir tarot açılımı kararsızlık anında farklı olasılıkları isimlendirir. Bazen numeroloji, kişinin kendi ritmini ve karar alma biçimini fark etmesi için sade bir ayna tutar.\\",\\"Pınar’ın kurucu yaklaşımında en kritik soru şudur: Kullanıcı seansa girmeden önce kendini daha güvende, daha bilgili ve daha az yalnız hissediyor mu? Bu yüzden platform yalnızca danışman listesi sunmaz; danışmanların hangi konularda çalıştığını, hangi dillerde hizmet verdiğini, hangi paketleri sunduğunu ve seansın nasıl ilerleyeceğini görünür kılar. Kullanıcı bir randevu oluşturduğunda ödeme, hatırlatma, mesajlaşma ve sesli görüşme adımları aynı akış içinde kalır. Böylece asıl odak teknik ayrıntılar değil, danışmanla kurulacak anlamlı görüşme olur.\\",\\"GoldMoodAstro’nun uzun vadeli vizyonu, Türkiye’den başlayarak farklı dillerde hizmet veren güvenilir bir ruhsal danışmanlık ağı kurmaktır. Bu ağda danışmanların emeği görünür olmalı, kullanıcıların soruları ciddiyetle karşılanmalı ve her içerik sorumlu bir dille yazılmalıdır. Astroloji, tarot veya numeroloji bir insanın hayatını tek başına yönetmez; ancak kişi kendi duygusunu, ihtiyacını ve olasılıklarını daha iyi gördüğünde karar alma biçimi değişebilir. Platformun varlık sebebi tam olarak bu farkındalık alanını büyütmektir.\\"]","en":"[\\"GoldMoodAstro grew out of Pınar Demircioğlu’s vision for spiritual consulting and her wish to bring together a more personal, trustworthy and accessible form of guidance. For Pınar, a good platform is not just fast screens; it is the invisible order that carries the user to the right expert, handles payment and booking safely, and removes technical friction when the session begins.\\",\\"That is why technology at GoldMoodAstro does not stand in front of spiritual guidance; it creates room for it. Users see profiles, expertise, reviews, session duration and fees transparently while choosing a consultant. Consultants work with a professional panel where they can manage their calendar, packages, messages and sessions. Our founder perspective is simple: spiritual guidance can be thoughtful, ethical and understandable in the digital world too.\\",\\"GoldMoodAstro’s first goal is not to reduce curiosity about astrology or tarot to a one-time entertainment moment, but to create a safe ground for conversation between consultant and user. Sometimes a birth chart helps someone notice repeating relationship patterns. Sometimes a tarot spread names different possibilities in a moment of uncertainty. Sometimes numerology offers a simple mirror for noticing one’s own rhythm and decision style.\\",\\"The central question in Pınar’s founding approach is this: does the user feel safer, better informed and less alone before entering a session? This is why the platform does more than list consultants; it makes visible what they work on, which languages they serve in, which packages they offer and how the session unfolds. When a user books, payment, reminders, messaging and voice session steps stay in one flow. The focus becomes the meaningful conversation, not technical details.\\",\\"GoldMoodAstro’s long-term vision is to build a trusted spiritual consulting network that starts in Turkey and serves in different languages. In this network, consultants’ work should be visible, users’ questions should be met seriously and every piece of content should be written responsibly. Astrology, tarot or numerology does not run a person’s life on its own; but when someone sees their feelings, needs and possibilities more clearly, the way they make decisions can change. The platform exists to grow exactly this field of awareness.\\"]","de":"[\\"Die Idee zu GoldMoodAstro entstand aus Pınar Demircioğlus Vision für spirituelle Beratung und dem Wunsch, Menschen eine persönlichere, vertrauenswürdigere und leichter erreichbare Begleitung anzubieten. Für Pınar besteht eine gute Plattform nicht nur aus schnellen Bildschirmen; sie ist eine unsichtbare Ordnung, die Nutzer zur passenden Expertin oder zum passenden Experten führt, Zahlung und Termin sicher löst und technische Details aus dem Weg nimmt, wenn die Sitzung beginnt.\\",\\"Deshalb steht Technologie bei GoldMoodAstro nicht vor der spirituellen Beratung, sondern schafft Raum für sie. Nutzer sehen beim Auswählen eines Beraters Profil, Fachgebiet, Bewertungen, Sitzungsdauer und Preis transparent. Berater arbeiten mit einem professionellen Panel, in dem sie Kalender, Pakete, Nachrichten und Gespräche verwalten können. Unsere Gründerperspektive ist einfach: Spirituelle Beratung kann auch digital achtsam, ethisch und verständlich sein.\\",\\"Das erste Ziel von GoldMoodAstro ist es nicht, Interesse an Astrologie oder Tarot auf einmalige Unterhaltung zu reduzieren, sondern eine sichere Gesprächsgrundlage zwischen Berater und Nutzer zu schaffen. Manchmal hilft ein Geburtshoroskop, wiederkehrende Beziehungsmuster zu erkennen. Manchmal benennt eine Tarotlegung in einem Moment der Unsicherheit verschiedene Möglichkeiten. Manchmal hält Numerologie einen einfachen Spiegel für den eigenen Rhythmus und die eigene Art zu entscheiden vor.\\",\\"Die wichtigste Frage in Pınars Gründungsansatz lautet: Fühlt sich der Nutzer vor der Sitzung sicherer, informierter und weniger allein? Deshalb zeigt die Plattform nicht nur eine Beraterliste; sie macht sichtbar, an welchen Themen Berater arbeiten, in welchen Sprachen sie beraten, welche Pakete sie anbieten und wie eine Sitzung abläuft. Wenn ein Nutzer einen Termin bucht, bleiben Zahlung, Erinnerung, Nachrichten und Sprachgespräch in demselben Ablauf. So steht nicht die Technik im Mittelpunkt, sondern das bedeutungsvolle Gespräch.\\",\\"Die langfristige Vision von GoldMoodAstro ist ein vertrauenswürdiges Netzwerk für spirituelle Beratung, das in der Türkei beginnt und in verschiedenen Sprachen dient. In diesem Netzwerk soll die Arbeit der Berater sichtbar sein, die Fragen der Nutzer ernst genommen werden und jeder Inhalt verantwortungsvoll formuliert sein. Astrologie, Tarot oder Numerologie steuern ein Leben nicht allein; doch wenn ein Mensch seine Gefühle, Bedürfnisse und Möglichkeiten klarer sieht, kann sich seine Art zu entscheiden verändern. Genau diesen Bewusstseinsraum möchte die Plattform vergrößern.\\"]"}}'),
('bcd74d0f-8863-d0e4-bd65-f667d96e769a', 'ui_about_founder_title', '*', '{"label":{"tr":"Kurucu Hikayesi","en":"Founder Story","de":"Gründungsgeschichte"}}'),
('2ea1d627-d2f1-b737-04e2-23a33348d325', 'ui_about_lead', '*', '{"label":{"tr":"GoldMoodAstro; astroloji, tarot, numeroloji ve ilişki dinamiklerini tek bir danışmanlık deneyiminde buluşturan bir platformdur. Amacımız insanlara kesin hükümler vermek değil, karar anlarında daha bilinçli, sakin ve kendilerine yakın hissettiren bir rehberlik alanı açmaktır.","en":"GoldMoodAstro brings astrology, tarot, numerology and relationship dynamics together in one consultation experience. Our aim is not to hand people absolute verdicts, but to open a guided space where decisions can feel more conscious, calmer and closer to the self.","de":"GoldMoodAstro verbindet Astrologie, Tarot, Numerologie und Beziehungsdynamiken in einer Beratungserfahrung. Unser Ziel ist es nicht, Menschen endgültige Urteile zu geben, sondern einen Raum für Orientierung zu öffnen, in dem Entscheidungen bewusster, ruhiger und näher am eigenen Gefühl getroffen werden können."}}'),
('ddf27065-1ef9-9c24-fbfd-5c0f91ae6482', 'ui_about_methodology_paragraphs', '*', '{"label":{"tr":"[\\"Astroloji tarafında hesaplama katmanımız Swiss Ephemeris yaklaşımını temel alır. Doğum haritası, gezegen konumları, evler, açılar ve yükselen burç gibi teknik başlıklar saniye hassasiyetinde ele alınır. Bu teknik hesaplama, danışmanın sezgisel ve yorumlayıcı emeğinin yerine geçmez; yorumun daha sağlam bir zemin üzerinde kurulmasına yardımcı olur.\\",\\"Tarot içeriklerinde Rider-Waite-Smith sembolizmi ana referans kabul edilir. Kartlar kesin gelecek bildirimi olarak değil; soru, duygu, davranış ve olasılıkları konuşulabilir hale getiren sembolik bir dil olarak ele alınır. Numeroloji tarafında isim ve doğum tarihi üzerinden hayat yolu, kader sayısı ve kişisel döngüler yorumlanır. Her yöntemde ortak ilkemiz aynıdır: kişiyi korkutmak yerine farkındalık, sorumluluk ve seçenek duygusunu güçlendirmek.\\",\\"İçeriklerimiz editoryal kontrolden geçer. AI destekli üretim kullanılan alanlarda amaç otomasyonla otorite taklidi yapmak değil; bilgiyi daha okunabilir, tutarlı ve erişilebilir hale getirmektir. GoldMoodAstro’da yayınlanan genel içerikler kişisel danışmanlık yerine geçmez. Kişisel harita, ilişki veya yaşam kararları için bire bir seans, kullanıcı bağlamını ve sorusunu dikkate aldığı için daha uygundur.\\",\\"Danışmanlık dili konusunda özellikle dikkat ettiğimiz birkaç sınır vardır. Kullanıcıya korku veren, bağımlılık oluşturan, kesin felaket veya kesin mucize vadeden ifadeler GoldMoodAstro yaklaşımına uygun değildir. Bir danışman güçlü bir sembol gördüğünde bile bunu kişinin seçimini elinden alacak şekilde değil, üzerinde düşünülebilecek bir tema olarak aktarmalıdır. İlişki, kariyer, aile veya ruh hali gibi hassas başlıklarda amaç yargılamak değil; kişinin kendini daha iyi duymasına, seçeneklerini ayırt etmesine ve gerekiyorsa profesyonel destek aramasına alan açmaktır.\\"]","en":"[\\"On the astrology side, our calculation layer is based on the Swiss Ephemeris approach. Birth charts, planetary positions, houses, aspects and rising signs are handled with second-level precision. This technical calculation does not replace the consultant’s intuitive and interpretive work; it helps build the interpretation on firmer ground.\\",\\"For tarot content, Rider-Waite-Smith symbolism is treated as the main reference. Cards are not presented as definite statements about the future, but as a symbolic language that makes questions, emotions, behaviors and possibilities discussable. In numerology, names and birth dates are interpreted through life path, destiny number and personal cycles. Our shared principle in every method is the same: strengthen awareness, responsibility and a sense of options instead of fear.\\",\\"Our content passes through editorial review. Where AI-assisted generation is used, the goal is not to imitate authority through automation, but to make information more readable, consistent and accessible. General content published on GoldMoodAstro does not replace personal consulting. For a personal chart, relationship or life decision, a one-to-one session is more appropriate because it considers the user’s context and question.\\",\\"There are a few boundaries we watch carefully in consulting language. Statements that create fear, dependency, certain catastrophe or certain miracles do not fit the GoldMoodAstro approach. Even when a consultant sees a strong symbol, it should be presented as a theme to reflect on, not as something that removes the person’s choice. In sensitive areas such as relationships, career, family or mood, the aim is not to judge, but to help the person hear themselves better, distinguish options and seek professional support when needed.\\"]","de":"[\\"Auf astrologischer Seite basiert unsere Berechnungsebene auf dem Swiss-Ephemeris-Ansatz. Geburtshoroskop, Planetenstände, Häuser, Aspekte und Aszendent werden mit Sekundenpräzision behandelt. Diese technische Berechnung ersetzt nicht die intuitive und interpretierende Arbeit des Beraters; sie hilft, die Deutung auf eine stabilere Grundlage zu stellen.\\",\\"Bei Tarot-Inhalten gilt die Rider-Waite-Smith-Symbolik als wichtigste Referenz. Karten werden nicht als sichere Zukunftsaussage verstanden, sondern als symbolische Sprache, die Fragen, Gefühle, Verhalten und Möglichkeiten besprechbar macht. In der Numerologie werden Name und Geburtsdatum über Lebensweg, Schicksalszahl und persönliche Zyklen gedeutet. Unser gemeinsames Prinzip in jeder Methode ist dasselbe: Bewusstsein, Verantwortung und Handlungsspielraum stärken statt Angst auszulösen.\\",\\"Unsere Inhalte durchlaufen eine redaktionelle Kontrolle. Wo KI-gestützte Erstellung eingesetzt wird, geht es nicht darum, Autorität durch Automatisierung zu imitieren, sondern Wissen lesbarer, konsistenter und zugänglicher zu machen. Allgemeine Inhalte auf GoldMoodAstro ersetzen keine persönliche Beratung. Für persönliche Horoskope, Beziehungen oder Lebensentscheidungen ist eine Einzelsitzung passender, weil sie den Kontext und die Frage des Nutzers berücksichtigt.\\",\\"Bei der Beratungssprache achten wir besonders auf klare Grenzen. Aussagen, die Angst machen, Abhängigkeit erzeugen oder sichere Katastrophen beziehungsweise sichere Wunder versprechen, passen nicht zum GoldMoodAstro-Ansatz. Auch wenn ein Berater ein starkes Symbol sieht, sollte es als Thema zum Nachdenken vermittelt werden, nicht als etwas, das der Person die Wahl nimmt. Bei sensiblen Themen wie Beziehung, Karriere, Familie oder Stimmung geht es nicht um Urteil, sondern darum, dass die Person sich besser hört, Optionen erkennt und bei Bedarf professionelle Unterstützung sucht.\\"]"}}'),
('304030bc-7437-d108-0790-056a10d83297', 'ui_about_methodology_title', '*', '{"label":{"tr":"Metodoloji","en":"Methodology","de":"Methodik"}}'),
('47da9349-eed6-f323-2d99-8384bc79a19b', 'ui_about_title', '*', '{"label":{"tr":"Ruhsal rehberliği daha anlaşılır, güvenilir ve erişilebilir yapmak için buradayız.","en":"We are here to make spiritual guidance clearer, more reliable and easier to access.","de":"Wir sind da, um spirituelle Beratung verständlicher, verlässlicher und leichter zugänglich zu machen."}}')
