('558dcdc9-cc69-a9b4-4903-361f8b284cc1', 'ui_extra_b4_rising_insight_p1_a', '*', '{"label":{"tr":"Yükselen burcunuz, doğduğunuz an ufuk çizgisinde yükselen burçtur ve dış dünyaya sunduğunuz maskenizi temsil eder.","en":"Your rising sign is the sign rising on the horizon at the moment of your birth and represents the mask you present to the outside world.","de":"Ihr Aszendent ist das Zeichen, das im Moment Ihrer Geburt am Horizont aufstieg, und steht für die Maske, die Sie der Außenwelt zeigen."}}'),
('251fcca0-c1cb-b37e-32df-ea110fd681b4', 'ui_extra_b4_rising_insight_p1_b', '*', '{"label": {"tr": "Bir", "en": "With a", "de": "Mit einem"}}'),
('1c711dbd-3262-070a-3d16-c7dc665b2668', 'ui_extra_b4_rising_insight_p1_c', '*', '{"label": {"tr": "yükselen olarak, insanlar sizi ilk tanıdıklarında bu burcun özelliklerini görürler.", "en": "rising, this is how people tend to read you when they first meet you.", "de": "Aszendenten nehmen andere Sie beim ersten Kennenlernen meist so wahr."}}'),
('b4a240bc-437a-ce5a-71a5-1b3bff750ac5', 'ui_extra_b4_rising_insight_p2', '*', '{"label":{"tr":"Hayata bakış açınız, fiziksel görünümünüz ve ilk tepkileriniz bu burcun enerjisiyle şekillenir. Bu sizin kozmik vitrininizdir.","en":"Your outlook on life, physical appearance and first reactions are shaped by this sign’s energy. It is your cosmic storefront.","de":"Ihre Sicht auf das Leben, Ihr äußeres Auftreten und Ihre ersten Reaktionen werden von der Energie dieses Zeichens geprägt. Es ist Ihr kosmisches Schaufenster."}}'),
