('04d5c084-1f18-4746-a90e-4c8ee9b9940e', 'ui_home_promises_1_text', '*', '{"label":{"tr":"Aboneliğinizi tek tıkla, hiçbir form doldurmadan veya bekleme süresi olmadan anında iptal edebilirsiniz. Şeffaflık ana ilkemizdir.","en":"You can cancel your subscription instantly with one click, without filling out any forms or waiting. Transparency is our core principle.","de":"Sie können Ihr Abonnement sofort mit einem Klick kündigen, ohne Formulare oder Wartezeit. Transparenz ist unser Grundprinzip."}}'),
('70adbd33-e91c-400e-b6b6-18dddd9c2c31', 'ui_home_promises_1_target', '*', '{"label":{"tr":"ŞEFFAFLIK","en":"TRANSPARENCY","de":"TRANSPARENZ"}}'),
('a8099608-a59c-4133-a3b0-e0f1b0742dd3', 'ui_home_promises_2_title', '*', '{"label":{"tr":"Her yorum size özel","en":"Every reading is unique to you","de":"Jede Deutung ist persönlich"}}'),
('1d6e1683-0c95-4656-bb0d-d36ba0b60b9f', 'ui_home_promises_2_text', '*', '{"label":{"tr":"Genel geçer yorumlar yerine, doğum haritanızın saniye hassasiyetindeki verilerinden beslenen kişisel rehberlik sunuyoruz.","en":"Instead of generic readings, we offer personal guidance fed by your birth chart data with second-level precision.","de":"Statt allgemeiner Deutungen bieten wir persönliche Orientierung auf Basis sekundengenauer Geburtshoroskop-Daten."}}'),
