('6ba24a36-77bd-450c-8acc-d6abaa807646', 'ui_home_promises_3_title', '*', '{"label":{"tr":"Telefon numaranız bizde yok","en":"We don’t have your phone number","de":"Wir haben Ihre Telefonnummer nicht"}}'),
('7f1032c4-8171-4a3b-94d3-18ad288fae7a', 'ui_home_promises_3_text', '*', '{"label":{"tr":"Mahremiyetinize saygı duyuyoruz. Kayıt sırasında telefon numaranızı istemiyoruz, tüm iletişim uygulama içinden sağlanır.","en":"We respect your privacy. We don’t ask for your phone number during registration; all communication is provided through the app.","de":"Wir respektieren Ihre Privatsphäre. Bei der Registrierung fragen wir nicht nach Ihrer Telefonnummer; die Kommunikation läuft über die App."}}'),
