('fb9b8f98-0b83-4389-b213-0507ea4387a2', 'ui_home_hybrid_title', '*', '{"label":{"tr":"AI Zekası, <em>İnsan</em> Sezgisi","en":"AI Intelligence, <em>Human</em> Intuition","de":"KI-Intelligenz, <em>menschliche</em> Intuition"}}'),
('70e12db7-7858-4ca1-87a6-499aa28edfb9', 'ui_home_hybrid_description', '*', '{"label":{"tr":"Gold Mood, modern teknolojiyi kadim bilgilerle birleştirir. Doğum haritanızı saniyeler içinde analiz eden AI ve derin ruhsal rehberlik sunan gerçek danışmanlar bir arada.","en":"Gold Mood combines modern technology with ancient wisdom. AI that analyzes your birth chart in seconds, and real consultants who offer deep spiritual guidance.","de":"Gold Mood verbindet moderne Technologie mit altem Wissen: KI analysiert Ihr Geburtshoroskop in Sekunden, echte Berater bieten tiefe spirituelle Begleitung."}}'),
('de95e8c9-5eb2-4c53-9c99-309f98e33828', 'ui_home_hybrid_ai_title', '*', '{"label":{"tr":"Hızlı & Analitik","en":"Fast & Analytical","de":"Schnell & analytisch"}}'),
('e7cd2b54-dadb-45a5-a8bf-ab994a56d21e', 'ui_home_hybrid_ai_text', '*', '{"label":{"tr":"AI motorumuz, karmaşık astrolojik verileri saniyeler içinde işler ve günlük yorumunuzu hazırlar.","en":"Our AI engine processes complex astrological data in seconds and prepares your daily reading.","de":"Unsere KI verarbeitet komplexe astrologische Daten in Sekunden und bereitet Ihre tägliche Deutung vor."}}'),
('7cf59e5c-a765-4851-a342-b9afa19e01a5', 'ui_home_hybrid_human_title', '*', '{"label":{"tr":"Derin & Sezgisel","en":"Deep & Intuitive","de":"Tief & intuitiv"}}'),
('8802cecb-25c4-4267-8438-8f8cb33f5436', 'ui_home_hybrid_human_text', '*', '{"label":{"tr":"Gerçek danışmanlarımız, AI’nın ötesine geçerek hayatınızdaki özel düğümleri çözer.","en":"Our real consultants go beyond AI to resolve the unique knots in your life.","de":"Unsere echten Berater gehen über KI hinaus und helfen, persönliche Knoten in Ihrem Leben zu lösen."}}'),
