('6ccf3d45-5333-4420-b1c6-1132a8b950be', 'ui_home_trust_1_desc', '*', '{"label":{"tr":"Kayıt için sadece e-posta. Apple ve Google girişiyle bunu da atlayabilirsiniz. Numaranız bizde yok; satılmasının yolu yok.","en":"Email only for registration. You can even skip this with Apple and Google login. We do not have your number; there is no way to sell it.","de":"Für die Registrierung reicht E-Mail. Mit Apple- oder Google-Login können Sie selbst das überspringen. Wir haben Ihre Nummer nicht; sie kann nicht verkauft werden."}}'),
('bfb27fcd-105c-49f3-90ca-bd90dcb970df', 'ui_home_trust_2_title', '*', '{"label":{"tr":"Hesabınızı silerseniz, gerçekten silinir.","en":"If you delete your account, it is truly deleted.","de":"Wenn Sie Ihr Konto löschen, wird es wirklich gelöscht."}}'),
('0de01b6a-51e0-40b4-a44c-1a36aaa1f2b4', 'ui_home_trust_2_desc', '*', '{"label":{"tr":"7 gün içinde tüm veriniz veritabanından kalıcı olarak kalkar. Soft delete yok, arka planda saklanan kopya yok.","en":"Within 7 days, all your data is permanently removed from the database. No soft delete, no copy stored in the background.","de":"Innerhalb von 7 Tagen werden alle Ihre Daten dauerhaft aus der Datenbank entfernt. Kein Soft Delete, keine Kopie im Hintergrund."}}'),
('7331f788-ea42-41aa-a27d-374c22b8d911', 'ui_home_trust_3_title', '*', '{"label":{"tr":"Verinizi indirme hakkınız vardır.","en":"You have the right to download your data.","de":"Sie haben das Recht, Ihre Daten herunterzuladen."}}'),
('8eec1584-f9c1-4b19-ae89-93dfef589183', 'ui_home_trust_3_desc', '*', '{"label":{"tr":"Tek tıkla tüm verinizi JSON olarak indirebilirsiniz. KVKK ve GDPR uyumu birinci günden mimaride.","en":"You can download all your data as JSON with a single click. KVKK and GDPR compliance built in from day one.","de":"Sie können alle Ihre Daten mit einem Klick als JSON herunterladen. KVKK- und DSGVO-Konformität ist von Anfang an eingebaut."}}'),
('1bca0ec5-c1c0-4ec5-8bc1-287299394a26', 'ui_home_trust_4_title', '*', '{"label":{"tr":"Üçüncü tarafa veri satışı yok.","en":"No data sale to third parties.","de":"Kein Verkauf von Daten an Dritte."}}'),
('089c9464-ca72-47b8-8a5c-2684401db3e5', 'ui_home_trust_4_desc', '*', '{"label":{"tr":"Reklam gelirimiz yok, veri ortaklığımız yok. Tek gelir kalemimiz açık fiyatlı aboneliğinizdir; başka yerden para kazanma derdimiz yok.","en":"We have no ad revenue, no data partnerships. Our only source of income is your transparent subscription; we have no intention of making money elsewhere.","de":"Wir haben keine Werbeeinnahmen und keine Datenpartnerschaften. Unsere einzige Einnahmequelle ist Ihr transparentes Abonnement; wir verdienen nicht anderswo an Ihnen."}}'),
